import React, { useContext } from "react";
import { FormContext } from "../Contexts/FormContext";

const  NumericBox = ({ eid, fieldname, cap, col, mn, ev, val, mxLen }) => {
  const { register } = useContext(FormContext);
  const { setValue } = useContext(FormContext);
    return (
      <div className={`${col} mb-3`}>
    <label htmlFor={fieldname} className={`${mn ? "required" : ""} form-label`}>{cap}</label>
    <input name={fieldname} type="number"  className="form-control" 
    {...register(fieldname, { required: mn, value: val })} />
  </div>
    )
  }
  

export default NumericBox